import numpy as np

class Layer:
    def __init__(self, input_size, output_size, activation_function):
        self.weights = np.random.randn(input_size, output_size) * 0.01
        self.biases = np.zeros((1, output_size))
        self.activation_function = activation_function
        self.input = None
        self.output = None

    def forward(self, input_data):
        self.input = input_data
        z = np.dot(input_data, self.weights) + self.biases
        self.output = self.activation_function(z)
        return self.output

    def backward(self, output_gradient, learning_rate):
        activation_gradient = self.activation_function.gradient(self.output)
        weighted_gradient = output_gradient * activation_gradient
        input_gradient = np.dot(weighted_gradient, self.weights.T)

        weights_gradient = np.dot(self.input.T, weighted_gradient)
        self.weights -= learning_rate * weights_gradient
        self.biases -= learning_rate * np.sum(weighted_gradient, axis=0, keepdims=True)

        return input_gradient

class ActivationFunction:
    @staticmethod
    def relu(x):
        return np.maximum(0, x)

    @staticmethod
    def relu_gradient(output):
        return (output > 0).astype(float)

    @staticmethod
    def sigmoid(x):
        return 1 / (1 + np.exp(-x))

    @staticmethod
    def sigmoid_gradient(output):
        return output * (1 - output)

    @staticmethod
    def softmax(x):
        exp_x = np.exp(x - np.max(x, axis=1, keepdims=True))
        return exp_x / np.sum(exp_x, axis=1, keepdims=True)

    @staticmethod
    def softmax_gradient(output):
        return output * (1 - output)

class NeuralNetwork:
    def __init__(self, input_size, output_size, hidden_layers, activation_functions):
        self.layers = []
        previous_size = input_size

        for i in range(len(hidden_layers)):
            self.layers.append(Layer(previous_size, hidden_layers[i], activation_functions[i]))
            previous_size = hidden_layers[i]

        self.layers.append(Layer(previous_size, output_size, ActivationFunction.softmax))

    def forward(self, input_data):
        for layer in self.layers:
            input_data = layer.forward(input_data)
        return input_data

    def backward(self, output_gradient, learning_rate):
        for layer in reversed(self.layers):
            output_gradient = layer.backward(output_gradient, learning_rate)

    def train(self, X, y, epochs, learning_rate):
        for epoch in range(epochs):
            output = self.forward(X)
            loss = self.loss(output, y)
            output_gradient = self.loss_gradient(output, y)
            self.backward(output_gradient, learning_rate)
            if epoch % 100 == 0:
                print(f'Epoch {epoch}, Loss: {loss}')

    def loss(self, output, y):
        return -np.mean(np.sum(y * np.log(output + 1e-9), axis=1))

    def loss_gradient(self, output, y):
        return output - y

