    X = np.array([[0, 0], [0, 1], [1, 0], [1, 1]])
    y = np.array([[1, 0], [0, 1], [0, 1], [1, 0]])  # One-hot encoding

    hidden_layers = [2]
    activation_functions = [ActivationFunction.relu]

    nn = NeuralNetwork(input_size=2, output_size=2, hidden_layers=hidden_layers, activation_functions=activation_functions)
    nn.train(X, y, epochs=1000, learning_rate=0.1)

    # Testing
