class Neuron:
    def __init__(self, num_inputs):
        self.weights = [random.uniform(-1, 1) for _ in range(num_inputs)]
        self.bias = random.uniform(-1, 1)
        self.output = 0

    def activate(self, inputs):
        total_input = sum(w * i for w, i in zip(self.weights, inputs)) + self.bias
        self.output = self.sigmoid(total_input)
        return self.output

    def sigmoid(self, x):
        return 1 / (1 + math.exp(-x))

    def sigmoid_derivative(self, output):
        return output * (1 - output)


class Layer:
    def __init__(self, num_neurons, num_inputs):
        self.neurons = [Neuron(num_inputs) for _ in range(num_neurons)]

    def forward(self, inputs):
        return [neuron.activate(inputs) for neuron in self.neurons]

    def backward(self, outputs, targets, learning_rate):
        for i, neuron in enumerate(self.neurons):
            error = targets[i] - outputs[i]
            for j in range(len(neuron.weights)):
                neuron.weights[j] += learning_rate * error * neuron.sigmoid_derivative(neuron.output) * outputs[j]
            neuron.bias += learning_rate * error * neuron.sigmoid_derivative(neuron.output)


class NeuralNetwork:
    def __init__(self, layer_sizes):
        self.layers = []
        for i in range(len(layer_sizes) - 1):
            self.layers.append(Layer(layer_sizes[i + 1], layer_sizes[i]))

    def forward(self, inputs):
        for layer in self.layers:
            inputs = layer.forward(inputs)
        return inputs

    def backward(self, outputs, targets, learning_rate):
        for layer in reversed(self.layers):
            layer.backward(outputs, targets, learning_rate)

    def train(self, inputs, targets, epochs, learning_rate):
        for _ in range(epochs):
            for input_data, target in zip(inputs, targets):
                output = self.forward(input_data)
                self.backward(output, target, learning_rate)

