class NeuralNetwork:
    def __init__(self, input_size, hidden_layers, output_size, activation_function='sigmoid'):
        self.input_size = input_size
        self.hidden_layers = hidden_layers
        self.output_size = output_size
        self.activation_function = activation_function
        self.weights = []
        self.biases = []
        self.initialize_network()

    def initialize_network(self):
        layer_sizes = [self.input_size] + self.hidden_layers + [self.output_size]
        for i in range(len(layer_sizes) - 1):
            weight_matrix = np.random.randn(layer_sizes[i], layer_sizes[i + 1]) * 0.01
            bias_vector = np.zeros((1, layer_sizes[i + 1]))
            self.weights.append(weight_matrix)
            self.biases.append(bias_vector)

    def activate(self, x):
        if self.activation_function == 'sigmoid':
            return 1 / (1 + np.exp(-x))
        elif self.activation_function == 'relu':
            return np.maximum(0, x)
        elif self.activation_function == 'tanh':
            return np.tanh(x)
        else:
            raise ValueError("Unsupported activation function")

    def activate_derivative(self, x):
        if self.activation_function == 'sigmoid':
            return x * (1 - x)
        elif self.activation_function == 'relu':
            return np.where(x > 0, 1, 0)
        elif self.activation_function == 'tanh':
            return 1 - np.square(x)
        else:
            raise ValueError("Unsupported activation function")

    def forward(self, x):
        self.layer_outputs = [x]
        for weight, bias in zip(self.weights, self.biases):
            x = self.activate(np.dot(x, weight) + bias)
            self.layer_outputs.append(x)
        return x

    def backward(self, x, y, learning_rate):
        output_error = self.layer_outputs[-1] - y
        for i in reversed(range(len(self.weights))):
            output_delta = output_error * self.activate_derivative(self.layer_outputs[i + 1])
            self.weights[i] -= np.dot(self.layer_outputs[i].T, output_delta) * learning_rate
            output_error = np.dot(output_delta, self.weights[i].T)

    def train(self, x, y, epochs, learning_rate):
        for epoch in range(epochs):
            self.forward(x)
            self.backward(x, y, learning_rate)

    def predict(self, x):
        return self.forward(x)

