        for i in range(len(self.weights)):
            z = self.dot_product(self.activations[-1], self.weights[i]) + self.biases[i]
            activation = [self.sigmoid(x) for x in z]
            self.activations.append(activation)
        return self.activations[-1]

    def backward(self, expected_output, learning_rate):
        output_error = [expected_output[i] - self.activations[-1][i] for i in range(len(expected_output))]
        deltas = [output_error[i] * self.sigmoid_derivative(self.activations[-1][i]) for i in range(len(output_error))]

        for i in reversed(range(len(self.weights))):
            for j in range(len(self.weights[i])):
                for k in range(len(deltas)):
                    self.weights[i][j][k] += learning_rate * deltas[k] * self.activations[i][j]
            if i > 0:
                deltas = self.dot_product(deltas, self.weights[i]) * self.sigmoid_derivative(self.activations[i])

