            bias = np.zeros((1, layers[i + 1]))
            self.weights.append(weight)
            self.biases.append(bias)

    def activation(self, z, activation_type='relu'):
        if activation_type == 'relu':
            return np.maximum(0, z)
        elif activation_type == 'sigmoid':
            return 1 / (1 + np.exp(-z))
        elif activation_type == 'tanh':
            return np.tanh(z)
        else:
            raise ValueError("Unsupported activation type")

    def activation_derivative(self, z, activation_type='relu'):
        if activation_type == 'relu':
            return (z > 0).astype(float)
        elif activation_type == 'sigmoid':
            sig = self.activation(z, 'sigmoid')
            return sig * (1 - sig)
        elif activation_type == 'tanh':
            return 1 - np.tanh(z) ** 2
        else:
            raise ValueError("Unsupported activation type")

    def forward(self, X):
        self.a = [X]
        for i in range(len(self.weights)):
            z = np.dot(self.a[i], self.weights[i]) + self.biases[i]
            a = self.activation(z)
            self.a.append(a)
        return self.a[-1]

    def backward(self, X, y, learning_rate=0.01, activation_type='relu'):
        m = y.shape[0]
        output = self.a[-1]
        loss = output - y
        dZ = loss / m * self.activation_derivative(output, activation_type)

        for i in reversed(range(len(self.weights))):
            dW = np.dot(self.a[i].T, dZ)
            dB = np.sum(dZ, axis=0, keepdims=True)
            dZ = np.dot(dZ, self.weights[i].T) * self.activation_derivative(self.a[i], activation_type)
            self.weights[i] -= learning_rate * dW
            self.biases[i] -= learning_rate * dB

    def train(self, X, y, epochs=1000, learning_rate=0.01, activation_type='relu'):
        for epoch in range(epochs):
            self.forward(X)
            self.backward(X, y, learning_rate, activation_type)

