            x = self.activation(x)
        return x

    def dot_product(self, weights, inputs):
        return [sum(w * i for w, i in zip(weight, inputs)) for weight in weights]

    def add_bias(self, x, bias):
        return [xi + bi for xi, bi in zip(x, bias)]

    def backward(self, x, y, learning_rate=0.01):
        output = self.forward(x)
        output_error = [o - t for o, t in zip(output, y)]
        for i in reversed(range(len(self.weights))):
            weight_gradient = self.calculate_gradient(output_error, self.weights[i])
            self.weights[i] = self.update_weights(self.weights[i], weight_gradient, learning_rate)
            output_error = self.dot_product(self.transpose(self.weights[i]), output_error)

    def calculate_gradient(self, output_error, weights):
        return [[error * xi for xi in weights_row] for weights_row, error in zip(weights, output_error)]

    def update_weights(self, weights, gradient, learning_rate):
        return [[w - learning_rate * g for w, g in zip(weights_row, gradient_row)] for weights_row, gradient_row in zip(weights, gradient)]

    def transpose(self, matrix):
        return list(map(list, zip(*matrix)))

