        self.weights = [random.uniform(-1, 1) for _ in range(num_inputs)]
        self.bias = random.uniform(-1, 1)
        self.output = 0
        self.delta = 0

    def activate(self, x):
        return 1 / (1 + math.exp(-x))

    def forward(self, inputs):
        total_input = sum(w * i for w, i in zip(self.weights, inputs)) + self.bias
        self.output = self.activate(total_input)
        return self.output

    def backward(self, inputs, learning_rate):
        self.delta = self.output * (1 - self.output) * (inputs[-1] - self.output)
        for i in range(len(self.weights)):
            self.weights[i] += learning_rate * self.delta * inputs[i]
        self.bias += learning_rate * self.delta


class Layer:
    def __init__(self, num_neurons, num_inputs):
        self.neurons = [Neuron(num_inputs) for _ in range(num_neurons)]

    def forward(self, inputs):
        return [neuron.forward(inputs) for neuron in self.neurons]

    def backward(self, inputs, learning_rate):
        for neuron in self.neurons:
            neuron.backward(inputs, learning_rate)


class NeuralNetwork:
    def __init__(self, layer_sizes):
        self.layers = []
        for i in range(len(layer_sizes) - 1):
            self.layers.append(Layer(layer_sizes[i + 1], layer_sizes[i]))

    def forward(self, inputs):
        for layer in self.layers:
            inputs = layer.forward(inputs)
        return inputs

    def backward(self, expected_output, learning_rate):
        for i in reversed(range(len(self.layers))):
            layer_output = [neuron.output for neuron in self.layers[i].neurons]
            if i == len(self.layers) - 1:
                for j in range(len(layer_output)):
                    self.layers[i].neurons[j].delta = layer_output[j] * (1 - layer_output[j]) * (expected_output[j] - layer_output[j])
            else:
                for j in range(len(layer_output)):
                    self.layers[i].neurons[j].delta = layer_output[j] * (1 - layer_output[j]) * sum(neuron.delta * neuron.weights[j] for neuron in self.layers[i + 1].neurons)
            self.layers[i].backward([neuron.output for neuron in self.layers[i - 1].neurons] if i > 0 else inputs, learning_rate)

    def train(self, training_data, expected_outputs, epochs, learning_rate):
        for _ in range(epochs):
            for inputs, expected_output in zip(training_data, expected_outputs):
                self.forward(inputs)
                self.backward(expected_output, learning_rate)


